# FindMyNyumba - fixed contact-landlord.html
# Run from D:\FindMyNyumba_Original
$ErrorActionPreference='Stop'
function Write-FileB64($p,$b){ $f=Join-Path (Get-Location) $p; $d=Split-Path $f -Parent; if(!(Test-Path $d)){New-Item -ItemType Directory -Force -Path $d|Out-Null}; [IO.File]::WriteAllBytes($f,[Convert]::FromBase64String($b)); Write-Host "  wrote $p" }
Write-FileB64 'frontend\contact-landlord.html' ''
Write-Host 'Done. Now: git add -A; git commit -m "fix: contact-landlord cleanup + logo"; git push origin feat/listing-media'
